def compute_score() -> tuple[str, float]:
    # Use ppt_diff to check for animation/transition changes
    extraneous_anim = [a for a in ppt_diff.added_animations if a.slide_id != '6']
    extraneous_anim += [a for a in ppt_diff.removed_animations if a.slide_id != '6']
    extraneous_anim += [a for a,_ in ppt_diff.modified_animations if a.slide_id != '6']
    extraneous_trans = [t for t in ppt_diff.added_transitions if t.slide_id != '6']
    extraneous_trans += [t for t in ppt_diff.removed_transitions if t.slide_id != '6']
    extraneous_trans += [t for t,_ in ppt_diff.modified_transitions if t.slide_id != '6']
    if extraneous_anim or extraneous_trans:
        return (f"Extraneous animation/transition changes detected.", 0.0)
    return ("No extraneous animation or transition changes detected.", 1.0)

def compute_score() -> tuple[str, float]:
    # Use ppt_diff and python-pptx to check for other changes to slide 6.
    # Check for notes changes, added/removed elements (except the border on the image)
    slide_mods = [pair for pair in ppt_diff.modified_slides if pair[0].slide_number == 6]
    notes_changed = False
    if slide_mods:
        orig_slide, mod_slide = slide_mods[0]
        if orig_slide.notes != mod_slide.notes:
            notes_changed = True
    # Now check for added/removed shapes except border on diagram image
    from pptx import Presentation
    prs_orig = Presentation(original_ppt_path)
    prs_mod = Presentation(modified_ppt_path)
    orig_slide = prs_orig.slides[5]
    mod_slide = prs_mod.slides[5]
    # Allow a change in shape count by +0 or +1 (for border addition)
    orig_shape_count = len(orig_slide.shapes)
    mod_shape_count = len(mod_slide.shapes)
    shape_diff = mod_shape_count - orig_shape_count
    if notes_changed:
        return ("Slide 6 notes changed.", 0.0)
    if abs(shape_diff) > 1:
        return ("More than one element added/removed on slide 6.", 0.0)
    # Could further check for text changes, but border shouldn't affect text
    return ("No extraneous changes to slide 6 content (only border addition).", 1.0)
